import { CreditCardOutlined, UserOutlined } from "@ant-design/icons"
import {
  Button,
  Card,
  Col,
  DatePicker,
  Drawer,
  Form,
  Input,
  Radio,
  Row,
} from "antd"
import dayjs from "dayjs"
import timezone from "dayjs/plugin/timezone"
import utc from "dayjs/plugin/utc"
import { useEffect, useState } from "react"
import { useSelector } from "react-redux"
import ButtonCustom from "src/components/MyButton/Button"
import notice from "src/components/Notice"
import { getRegexMobile } from "src/lib/stringsUtils"
import {
  validateBirthDate,
  validateDate,
} from "src/pages/SUPPORTPAGES/ScanQRInfo/utils/cccdUtils"
import MemberService from "src/services/MemberService"

dayjs.extend(utc)
dayjs.extend(timezone)

const MemberDetailForm = ({
  visible,
  onCancel,
  onSuccess,
  selectedPlan,
  memberDetail,
}) => {
  const [form] = Form.useForm()
  const [loading, setLoading] = useState(false)
  const [isMobile, setIsMobile] = useState(window.innerWidth < 768)

  const { userInfo } = useSelector(state => state?.appGlobal)

  const updateMemberDetail = async formData => {
    try {
      const res = await MemberService.updateMemberDetailToUpgrade(formData)

      notice({
        msg: "Cập nhật thông tin thành công",
        isSuccess: true,
      })
      return true
    } catch (error) {
      console.log("error updateMemberDetail", error)
      return false
    }
  }

  const handleSubmit = async values => {
    try {
      setLoading(true)

      const formData = {
        MemberId: userInfo?.MemberID,
        FullName: values.FullName,
        DateOfBirth: values.DateOfBirth
          ? dayjs(values.DateOfBirth).utc().format()
          : null,
        Gender: values.Gender === "Nam" ? 1 : values.Gender === "Nữ" ? 2 : null,
        ResidenceAddress: values.ResidenceAddress,
        Identification: values.Identification,
        IdentificationIssueDate: values.IdentificationIssueDate
          ? dayjs(values.IdentificationIssueDate).utc().format()
          : null,
        IdentificationIssuePlace: values.IdentificationIssuePlace,
        Occupation: values.Occupation,
        PhoneNumber: values.PhoneNumber,
        PlaceOfBirth: values.PlaceOfBirth,
        Hometown: values.Hometown,
        EducationLevel: values.EducationLevel,
        ProfessionalLevel: values.ProfessionalLevel,
        WorkingAt: values.WorkingAt,
        OfficeAddress: values.OfficeAddress,
        ContactAddress: values.ContactAddress,
        OfficePhone: values.OfficePhone,
        HomePhone: values.HomePhone,
        Fax: values.Fax,
        Email: values.Email,
      }

      const [updateResult, pdfResult] = await Promise.allSettled([
        updateMemberDetail(formData),
        MemberService.uploadMembershipUpgradeForm(formData),
      ])

      if (updateResult.status === "fulfilled" && updateResult.value) {
        let pdfUrl = null

        if (pdfResult.status === "fulfilled" && pdfResult.value?.Object) {
          pdfUrl = pdfResult.value.Object
        }

        onSuccess(formData, pdfUrl)
      } else {
        console.error("Update failed:", updateResult.reason)
      }
    } catch (error) {
      console.error("Submit error:", error)
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => {
    const handleResize = () => {
      setIsMobile(window.innerWidth < 768)
    }

    window.addEventListener("resize", handleResize)
    return () => window.removeEventListener("resize", handleResize)
  }, [])

  useEffect(() => {
    if (visible && memberDetail) {
      form.setFieldsValue({
        FullName: memberDetail.FullName || "",
        Gender:
          memberDetail.Gender === 2
            ? "Nữ"
            : memberDetail.Gender === 1
            ? "Nam"
            : "",
        DateOfBirth: memberDetail.DateOfBirth
          ? dayjs(memberDetail.DateOfBirth)
          : null,
        PlaceOfBirth: memberDetail.PlaceOfBirth || "",
        Hometown: memberDetail.Hometown || "Việt Nam",
        ResidenceAddress: memberDetail.ResidenceAddress || "",
        Identification: memberDetail.Identification || "",
        IdentificationIssueDate: memberDetail.IdentificationIssueDate
          ? dayjs(memberDetail.IdentificationIssueDate)
          : null,
        IdentificationIssuePlace: memberDetail.IdentificationIssuePlace || "",
        Occupation: memberDetail.Occupation || "",
        WorkingAt: memberDetail.WorkingAt || "",
        EducationLevel: memberDetail.EducationLevel || "",
        ProfessionalLevel: memberDetail.ProfessionalLevel || "",
        OfficeAddress: memberDetail.OfficeAddress || "",
        ContactAddress: memberDetail.ContactAddress || "",
        OfficePhone: memberDetail.OfficePhone || "",
        HomePhone: memberDetail.HomePhone || "",
        PhoneNumber: memberDetail.PhoneNumber || "",
        Fax: memberDetail.Fax || "",
        Email: memberDetail.Email || "",
      })
    }
  }, [visible, memberDetail, form])

  useEffect(() => {
    if (!visible) {
      form.resetFields()
    }
  }, [visible, form])

  return (
    <Drawer
      title={
        <div style={{ display: "flex", alignItems: "center", gap: "8px" }}>
          <UserOutlined />
          <span>Cập nhật thông tin hội viên</span>
        </div>
      }
      open={visible}
      onClose={onCancel}
      width={isMobile ? "100%" : "85%"}
      styles={{
        body: { paddingBottom: 60, backgroundColor: "#DAF2EB" },
      }}
      destroyOnClose
    >
      <Form
        form={form}
        layout="vertical"
        onFinish={handleSubmit}
        scrollToFirstError
      >
        {/* Thông tin cá nhân cơ bản */}
        <Card className="card-title-section-row" size="small">
          <Row gutter={[16, 16]}>
            <Col xs={24} sm={24} md={24} lg={24}>
              <Form.Item
                label="Họ tên"
                name="FullName"
                rules={[{ required: true, message: "Vui lòng nhập họ tên!" }]}
              >
                <Input placeholder="Nhập họ tên đầy đủ" />
              </Form.Item>
            </Col>
          </Row>
        </Card>

        <Card className="card-title-section-row" size="small">
          <Row gutter={[16, 16]}>
            <Col xs={24} sm={24} md={24} lg={24}>
              <Form.Item
                label="Ngày sinh"
                name="DateOfBirth"
                rules={[
                  {
                    required: true,
                    validator: validateBirthDate,
                  },
                ]}
              >
                <DatePicker
                  placeholder="Chọn ngày sinh"
                  format="DD/MM/YYYY"
                  style={{ width: "100%" }}
                />
              </Form.Item>
            </Col>
          </Row>
        </Card>
        <Card className="card-title-section-row" size="small">
          <Row gutter={[16, 16]}>
            <Col xs={24} sm={24} md={24} lg={24}>
              <Form.Item
                label="Giới tính"
                name="Gender"
                rules={[
                  { required: true, message: "Vui lòng chọn giới tính!" },
                ]}
              >
                <Radio.Group
                  style={{
                    display: "flex",
                    flexDirection: "column",
                    gap: "8px",
                  }}
                >
                  <Radio value="Nam">Nam</Radio>
                  <Radio value="Nữ">Nữ</Radio>
                </Radio.Group>
              </Form.Item>
            </Col>
          </Row>
        </Card>

        {/* Thông tin nơi sinh và quê quán */}
        <Card className="card-title-section-row" size="small">
          <Row gutter={[16, 16]}>
            <Col xs={24} sm={24} md={24} lg={24}>
              <Form.Item label="Nơi sinh" name="PlaceOfBirth">
                <Input placeholder="Nhập nơi sinh" />
              </Form.Item>
            </Col>
          </Row>
        </Card>

        <Card className="card-title-section-row" size="small">
          <Row gutter={[16, 16]}>
            <Col xs={24} sm={24} md={24} lg={24}>
              <Form.Item label="Quê quán" name="Hometown">
                <Input placeholder="Nhập quê quán" />
              </Form.Item>
            </Col>
          </Row>
        </Card>

        <Card className="card-title-section-row" size="small">
          <Row gutter={[16, 16]}>
            <Col xs={24} sm={24} md={24} lg={24}>
              <Form.Item
                label="Nơi đăng ký hộ khẩu thường trú"
                name="ResidenceAddress"
                rules={[
                  { required: true, message: "Vui lòng nhập nơi thường trú!" },
                ]}
              >
                <Input placeholder="Nhập nơi thường trú" />
              </Form.Item>
            </Col>
          </Row>
        </Card>

        <Card className="card-title-section-row" size="small">
          <Row gutter={[16, 16]}>
            <Col xs={24} sm={24} md={24} lg={24}>
              <Form.Item
                label="Số CCCD"
                name="Identification"
                rules={[
                  { required: true, message: "Vui lòng nhập số CCCD!" },
                  {
                    pattern: /^\d{12}$/,
                    message: "Số CCCD phải có 12 chữ số",
                  },
                ]}
              >
                <Input placeholder="Nhập số CCCD" />
              </Form.Item>
            </Col>
          </Row>
        </Card>

        <Card className="card-title-section-row" size="small">
          <Row gutter={[16, 16]}>
            <Col xs={24} sm={24} md={24} lg={24}>
              <Form.Item
                label="Cấp ngày"
                name="IdentificationIssueDate"
                rules={[
                  {
                    required: true,
                    // message: "Vui lòng chọn ngày cấp!",
                    validator: validateDate,
                  },
                ]}
              >
                <DatePicker
                  placeholder="Chọn ngày cấp"
                  format="DD/MM/YYYY"
                  style={{ width: "100%" }}
                />
              </Form.Item>
            </Col>
          </Row>
        </Card>

        <Card className="card-title-section-row" size="small">
          <Row gutter={[16, 16]}>
            <Col xs={24} sm={24} md={24} lg={24}>
              <Form.Item
                label="Nơi cấp"
                name="IdentificationIssuePlace"
                rules={[{ required: true, message: "Vui lòng nhập nơi cấp!" }]}
              >
                <Input placeholder="Nhập nơi cấp CCCD" />
              </Form.Item>
            </Col>
          </Row>
        </Card>

        {/* Thông tin trình độ */}
        <Card className="card-title-section-row" size="small">
          <Row gutter={[16, 16]}>
            <Col xs={24} sm={24} md={24} lg={24}>
              <Form.Item label="Trình độ văn hóa" name="EducationLevel">
                <Input placeholder="Nhập trình độ văn hóa" />
              </Form.Item>
            </Col>
          </Row>
        </Card>

        <Card className="card-title-section-row" size="small">
          <Row gutter={[16, 16]}>
            <Col xs={24} sm={24} md={24} lg={24}>
              <Form.Item label="Trình độ chuyên môn" name="ProfessionalLevel">
                <Input placeholder="Nhập trình độ chuyên môn" />
              </Form.Item>
            </Col>
          </Row>
        </Card>

        {/* Thông tin công việc */}
        <Card className="card-title-section-row" size="small">
          <Row gutter={[16, 16]}>
            <Col xs={24} sm={24} md={24} lg={24}>
              <Form.Item label="Nơi làm việc" name="WorkingAt">
                <Input placeholder="Nhập nơi làm việc" />
              </Form.Item>
            </Col>
          </Row>
        </Card>
        <Card className="card-title-section-row" size="small">
          <Row gutter={[16, 16]}>
            <Col xs={24} sm={24} md={24} lg={24}>
              <Form.Item
                label="Chức vụ, nghề nghiệp"
                name="Occupation"
                rules={[{ required: true, message: "Vui lòng nhập chức vụ!" }]}
              >
                <Input placeholder="Nhập chức vụ, nghề nghiệp" />
              </Form.Item>
            </Col>
          </Row>
        </Card>

        {/* Thông tin địa chỉ liên hệ */}
        <Card className="card-title-section-row" size="small">
          <Row gutter={[16, 16]}>
            <Col xs={24} sm={24} md={24} lg={24}>
              <Form.Item
                label="Địa chỉ cơ quan"
                name="OfficeAddress"
                rules={[
                  { required: true, message: "Vui lòng nhập địa chỉ cơ quan!" },
                ]}
              >
                <Input placeholder="Nhập địa chỉ cơ quan" />
              </Form.Item>
            </Col>
          </Row>
        </Card>
        <Card className="card-title-section-row" size="small">
          <Row gutter={[16, 16]}>
            <Col xs={24} sm={24} md={24} lg={24}>
              <Form.Item
                label="Địa chỉ liên hệ"
                name="ContactAddress"
                rules={[
                  { required: true, message: "Vui lòng nhập địa chỉ liên hệ!" },
                ]}
              >
                <Input placeholder="Nhập địa chỉ liên hệ" />
              </Form.Item>
            </Col>
          </Row>
        </Card>

        <Card className="card-title-section-row" size="small">
          <Row gutter={[16, 16]}>
            <Col xs={24} sm={24} md={24} lg={24}>
              <Form.Item
                label="Điện thoại cơ quan"
                name="OfficePhone"
                rules={[
                  {
                    pattern: getRegexMobile(),
                    message: "Số điện thoại không hợp lệ",
                  },
                ]}
              >
                <Input placeholder="Nhập SĐT cơ quan" />
              </Form.Item>
            </Col>
          </Row>
        </Card>
        <Card className="card-title-section-row" size="small">
          <Row gutter={[16, 16]}>
            <Col xs={24} sm={24} md={24} lg={24}>
              <Form.Item
                label="Điện thoại nhà riêng"
                name="HomePhone"
                rules={[
                  {
                    pattern: getRegexMobile(),
                    message: "Số điện thoại không hợp lệ",
                  },
                ]}
              >
                <Input placeholder="Nhập ĐT nhà riêng" />
              </Form.Item>
            </Col>
          </Row>
        </Card>
        <Card className="card-title-section-row" size="small">
          <Row gutter={[16, 16]}>
            <Col xs={24} sm={24} md={24} lg={24}>
              <Form.Item
                label="Điện thoại di động"
                name="PhoneNumber"
                rules={[
                  {
                    required: true,
                    message: "Vui lòng nhập số điện thoại",
                  },
                  {
                    pattern: getRegexMobile(),
                    message: "Số điện thoại không hợp lệ",
                  },
                ]}
              >
                <Input placeholder="Nhập ĐT di động" />
              </Form.Item>
            </Col>
          </Row>
        </Card>
        <Card className="card-title-section-row" size="small">
          <Row gutter={[16, 16]}>
            <Col xs={24} sm={24} md={24} lg={24}>
              <Form.Item label="Fax" name="Fax">
                <Input placeholder="Nhập số Fax" />
              </Form.Item>
            </Col>
          </Row>
        </Card>
        <Card className="card-title-section-row" size="small">
          <Row gutter={[16, 16]}>
            <Col xs={24} sm={24} md={24} lg={24}>
              <Form.Item
                label="Email"
                name="Email"
                rules={[
                  { required: true, message: "Vui lòng nhập email!" },
                  { type: "email", message: "Email không hợp lệ!" },
                ]}
              >
                <Input placeholder="Nhập địa chỉ email" />
              </Form.Item>
            </Col>
          </Row>
        </Card>
      </Form>

      <div
        style={{
          position: "absolute",
          right: 0,
          bottom: 0,
          width: "100%",
          borderTop: "1px solid #e9e9e9",
          padding: "10px 16px",
          background: "#fff",
          textAlign: "right",
          gap: "8px",
          display: "flex",
          justifyContent: "flex-end",
        }}
      >
        <Button
          style={{
            borderColor: "#d9d9d9",
            color: "#595959",
          }}
          onClick={onCancel}
          disabled={loading}
        >
          Hủy
        </Button>
        <ButtonCustom
          type="primary"
          onClick={() => form.submit()}
          loading={loading}
          icon={<CreditCardOutlined />}
        >
          Cập nhật và tiếp tục
        </ButtonCustom>
      </div>
    </Drawer>
  )
}

export default MemberDetailForm
