import { CheckOutlined, CreditCardOutlined } from "@ant-design/icons"
import {
  Badge,
  Button,
  Card,
  Checkbox,
  Col,
  message,
  Modal,
  QRCode,
  Result,
  Row,
  Typography,
} from "antd"
import { useEffect, useState } from "react"
import { useSelector } from "react-redux"
import DrawerViewPDF from "src/components/DrawerViewPDF"
import ButtonCustom from "src/components/MyButton/Button"
import notice from "src/components/Notice"
import signalRService from "src/components/SocketWrapper"
import MemberService from "src/services/MemberService"
import PackageService from "src/services/Package"
import PaymentService from "src/services/Payment"
import MemberDetailForm from "./MemberDetailForm"
import "./MembershipUpgrade.scss"

const { Title, Paragraph, Text } = Typography

const MembershipUpgrade = () => {
  const [selectedPlan, setSelectedPlan] = useState(null)
  const [showPaymentModal, setShowPaymentModal] = useState(false)
  const [showRegistrationModal, setShowRegistrationModal] = useState(false)
  const [showPdfModal, setShowPdfModal] = useState(false)
  const [activePopular, setActivePopular] = useState("")
  const [lstPacket, setLstPacket] = useState([])
  const [loading, setLoading] = useState(false)
  const [confirmedRead, setConfirmedRead] = useState(false)

  const [qrPayment, setQrPayment] = useState("")
  const [modalQr, setModalQr] = useState(false)

  const [payMentSuccess, setPayMentSuccess] = useState(false)
  const [modalPayMentSuccess, setModalPayMentSuccess] = useState(false)

  const [pdfFileUrl, setPdfFileUrl] = useState("")
  const [pdfFileName, setPdfFileName] = useState("")
  const [pdfLoading, setPdfLoading] = useState(false)

  const [memberDetail, setMemberDetail] = useState(null)

  const {
    userInfo,
    userInfo: { PackageName },
  } = useSelector(state => state?.appGlobal)

  const getListPackage = async () => {
    try {
      const param = {
        PageSize: 1000,
        CurrentPage: 1,
        TextSearch: "",
        Status: 1,
        MemberType: 2,
      }

      const res = await PackageService.getListPackage(param)
      if (res?.isError) return
      setLstPacket(res?.Object?.ListPackage)
      setActivePopular(res?.Object?.ListPackage[1]?.PackageID)
    } catch (error) {
      console.log("error getListPackage", error)
    }
  }

  const getMemberDetail = async () => {
    try {
      const params = {
        MemberID: userInfo.MemberID,
      }
      const res = await MemberService.getMemberDetailToUpgrade(params)

      if (res?.Object) {
        setMemberDetail(res.Object)
        return res.Object
      }
      return null
    } catch (error) {
      console.log("error getMemberDetail", error)
      return null
    }
  }

  const viewMembershipUpgradeForm = async formData => {
    try {
      const res = await MemberService.uploadMembershipUpgradeForm(formData)
      const viewUrl = res?.Object
      return viewUrl
    } catch (error) {
      console.error("Error in viewMembershipUpgradeForm:", error)
      return null
    }
  }

  const createPaymentUrl = async planData => {
    try {
      const resPayment = await PaymentService.createPaymentUrl({
        PackageId: planData.PackageID,
        Description: "",
        ReturnUrl: "",
        CancelUrl: "",
      })

      if (resPayment?.isError) {
        setModalQr(false)
        return
      }

      if (!resPayment?.Object?.IsSuccess) {
        notice({
          msg: resPayment?.Object?.Message,
          isSuccess: false,
        })
        return
      }

      setQrPayment(resPayment?.Object?.Data?.CreatePaymentResult)
      setModalQr(true)
    } catch (error) {
      console.error("Payment error:", error)
      message.error("Có lỗi xảy ra: " + error.message)
    } finally {
      setShowPaymentModal(false)
      setLoading(false)
    }
  }

  // Bước 1: Chọn gói -> gọi API memberDetail và hiển thị form điền thông tin
  const handlePlanSelect = async plan => {
    setSelectedPlan(plan)
    const memberDetailData = await getMemberDetail()
    if (memberDetailData) {
      setShowRegistrationModal(true)
    }
  }

  // Bước 2: Xử lý khi form submit thành công - kết hợp cả 2 cách tối ưu
  const handleMemberDetailSuccess = async (formData, pdfUrl = null) => {
    try {
      setShowRegistrationModal(false)

      if (pdfUrl) {
        setPdfFileUrl(pdfUrl)
        setPdfFileName(
          "ĐƠN XIN THAM GIA HIỆP HỘI TƯ VẤN NÂNG CAO SỨC KHỎE VIỆT NAM.pdf",
        )
        setConfirmedRead(false)
        setPdfLoading(false)
        setShowPdfModal(true)
      } else {
        setPdfFileUrl("")
        setPdfFileName(
          "ĐƠN XIN THAM GIA HIỆP HỘI TƯ VẤN NÂNG CAO SỨC KHỎE VIỆT NAM.pdf",
        )
        setConfirmedRead(false)
        setPdfLoading(true)
        setShowPdfModal(true)

        // Gọi API tạo PDF trong background
        const viewUrl = await viewMembershipUpgradeForm(formData)
        if (viewUrl) {
          console.log("✅ PDF ready from fallback API call")
          setPdfFileUrl(viewUrl)
          setPdfLoading(false)
        } else {
          console.error("❌ Both PDF generation methods failed")
          setPdfLoading(false)
          notice({
            msg: "Không thể tạo file PDF, chuyển thẳng sang thanh toán",
            isSuccess: false,
          })
          setShowPdfModal(false)
          setShowPaymentModal(true)
        }
      }
    } catch (error) {
      console.error("Error in handleMemberDetailSuccess:", error)
      setPdfLoading(false)
      setShowPdfModal(false)
      setShowPaymentModal(true)
    }
  }

  // Bước 3: Sau khi xem PDF và confirm -> hiển thị modal thanh toán
  const handlePdfModalConfirm = () => {
    if (!confirmedRead) {
      message.warning("Vui lòng xác nhận đã đọc điều khoản và điều kiện!")
      return
    }

    if (pdfLoading) {
      message.warning("Vui lòng chờ file PDF tải xong!")
      return
    }

    setShowPdfModal(false)
    setShowPaymentModal(true)
  }

  // Bước 4: Xác nhận thanh toán -> tạo QR code
  const handleConfirmPayment = () => {
    setLoading(true)
    if (selectedPlan) {
      createPaymentUrl(selectedPlan)
    }
  }

  const formatCurrency = amount => {
    return new Intl.NumberFormat("vi-VN", {
      style: "currency",
      currency: "VND",
    }).format(amount)
  }

  const handleCloseModalQr = async qrPayment => {
    try {
      const res = await PaymentService.cancelPayment({
        OrderCode: qrPayment.orderCode,
      })

      if (res?.isError) return

      notice({
        msg: res?.Object,
      })
    } catch (error) {
      console.log("error", error)
    } finally {
      setModalQr(false)
      setQrPayment("")
    }
  }

  useEffect(() => {
    getListPackage()
  }, [])

  useEffect(() => {
    let isMounted = true

    const initSignalR = async () => {
      try {
        await signalRService.startConnection()
        if (!isMounted) return
        signalRService.on("PaymentResult", data => {
          if (data) {
            setModalQr(false)
            setPayMentSuccess(true)
            setModalPayMentSuccess(true)
          } else {
            setModalQr(false)
            setPayMentSuccess(false)
            setModalPayMentSuccess(true)
          }
        })
      } catch (err) {
        console.error("SignalR init error:", err)
      }
    }

    initSignalR()

    return () => {
      isMounted = false
      signalRService.off("PaymentResult")
    }
  }, [])

  return (
    <div className="membership-upgrade">
      <div className="membership-upgrade__container">
        <div className="membership-upgrade__header">
          <Title level={2} className="membership-upgrade__title">
            Nâng cấp gói hội viên
          </Title>
          <Paragraph className="membership-upgrade__description">
            Chọn gói hội viên phù hợp để tận hưởng đầy đủ các quyền lợi và dịch
            vụ của hiệp hội
          </Paragraph>
        </div>

        <Row gutter={[24, 24]} className="membership-upgrade__cards">
          {lstPacket.length > 0 &&
            lstPacket?.map((item, idx) => (
              <Col xs={24} md={8} key={item.PackageID}>
                <Card
                  className={`membership-card ${
                    activePopular === item.PackageID ? "active" : ""
                  }`}
                  onMouseEnter={() => setActivePopular(item.PackageID)}
                  hoverable
                >
                  {item.PackageName === PackageName && (
                    <Badge.Ribbon
                      text="Đã sở hữu"
                      color="blue"
                      className="membership-card__ribbon"
                    >
                      <div />
                    </Badge.Ribbon>
                  )}

                  <div className="membership-card__body">
                    <div className="membership-card__header">
                      {/* <div className={`membership-card__icon`}>
                        {getRandomIcon()}
                      </div> */}
                      <Title level={4} className="membership-card__name">
                        {item.PackageName}
                      </Title>
                      <div className="membership-card__price">
                        <Text className="membership-card__price-amount">
                          {formatCurrency(item.Price)}
                        </Text>
                      </div>
                    </div>

                    <div className="membership-card__content">
                      <ul className="membership-card__features">
                        {item.listMemberRanks.map(listMemberRank => (
                          <li
                            key={listMemberRank.MemberRankID}
                            className="membership-card__feature"
                          >
                            <CheckOutlined className="membership-card__check" />
                            <span>{listMemberRank.RankName}</span>
                          </li>
                        ))}
                      </ul>
                    </div>
                  </div>

                  <div className="membership-card__footer">
                    <Button
                      size="large"
                      className="membership-card__button"
                      block
                      onClick={() => handlePlanSelect(item)}
                      icon={<CreditCardOutlined />}
                    >
                      Nâng cấp ngay
                    </Button>
                  </div>
                </Card>
              </Col>
            ))}
        </Row>
      </div>

      {/* Member Detail Form Component - Bước 2 với API song song */}
      <MemberDetailForm
        visible={showRegistrationModal}
        onCancel={() => setShowRegistrationModal(false)}
        onSuccess={handleMemberDetailSuccess}
        selectedPlan={selectedPlan}
        memberDetail={memberDetail}
      />

      {/* PDF Modal - Bước 3 với loading state */}
      <DrawerViewPDF
        open={showPdfModal}
        onClose={() => setShowPdfModal(false)}
        fileUrl={pdfFileUrl}
        attachmentName={pdfFileName}
        title="ĐƠN XIN THAM GIA HIỆP HỘI TƯ VẤN NÂNG CAO SỨC KHỎE VIỆT NAM.pdf"
        loading={pdfLoading}
        placement="right"
        width={1024}
        titleDrawer
        subFooter={() => (
          <>
            <Checkbox
              checked={confirmedRead}
              onChange={e => setConfirmedRead(e.target.checked)}
              style={{ marginRight: "auto", alignItems: "center" }}
              disabled={pdfLoading}
            >
              Tôi đã đọc và xác nhận thông tin trong đơn là chính xác
            </Checkbox>
            <ButtonCustom
              type="primary"
              onClick={handlePdfModalConfirm}
              disabled={!confirmedRead || pdfLoading}
              icon={<CreditCardOutlined />}
              style={{ marginRight: "8px" }}
              loading={pdfLoading}
            >
              {pdfLoading ? "Đang tải..." : "Tiếp tục thanh toán"}
            </ButtonCustom>
          </>
        )}
      />

      {/* Payment Confirmation Modal - Bước 4 */}
      <Modal
        title={
          <div style={{ display: "flex", alignItems: "center", gap: "8px" }}>
            <CreditCardOutlined />
            <span>Xác nhận thanh toán</span>
          </div>
        }
        open={showPaymentModal}
        onCancel={() => setShowPaymentModal(false)}
        footer={[
          <Button
            style={{ borderColor: "#01b39f", color: "#01b39f" }}
            key="cancel"
            onClick={() => setShowPaymentModal(false)}
          >
            Hủy
          </Button>,
          <ButtonCustom
            key="confirm"
            type="primary"
            onClick={handleConfirmPayment}
            icon={<CreditCardOutlined />}
            loading={loading}
          >
            Thanh toán ngay
          </ButtonCustom>,
        ]}
        width={550}
      >
        {selectedPlan && (
          <div style={{ padding: "16px 0" }}>
            <div style={{ textAlign: "center", marginBottom: "24px" }}>
              <div
                style={{
                  fontSize: "24px",
                  color: "#1890ff",
                  marginBottom: "8px",
                }}
              >
                {selectedPlan?.icon}
              </div>
              <Title level={4} style={{ margin: "8px 0" }}>
                {selectedPlan?.PackageName}
              </Title>
            </div>

            <div
              style={{
                background: "#f5f5f5",
                padding: "16px",
                borderRadius: "8px",
                marginBottom: "16px",
              }}
            >
              <div
                style={{
                  display: "flex",
                  justifyContent: "space-between",
                  alignItems: "center",
                }}
              >
                <Text strong>Số tiền thanh toán:</Text>
                <Text
                  style={{
                    fontSize: "20px",
                    color: "#ff4d4f",
                    fontWeight: "bold",
                  }}
                >
                  {formatCurrency(selectedPlan?.Price)}
                </Text>
              </div>
            </div>

            <Paragraph
              type="secondary"
              style={{ fontSize: "12px", textAlign: "center" }}
            >
              Bạn sẽ được chuyển hướng đến cổng thanh toán an toàn để hoàn tất
              giao dịch.
            </Paragraph>
          </div>
        )}
      </Modal>

      {/* modal QR */}
      {qrPayment && qrPayment.qrCode && (
        <Modal
          title={
            <div style={{ display: "flex", alignItems: "center", gap: "8px" }}>
              <CreditCardOutlined />
              <span>Quét mã QR để thanh toán</span>
            </div>
          }
          open={modalQr}
          onCancel={() => handleCloseModalQr(qrPayment)}
          footer={[
            <ButtonCustom
              key="cancel"
              onClick={() => handleCloseModalQr(qrPayment)}
            >
              Hủy
            </ButtonCustom>,
          ]}
          width={500}
        >
          <div style={{ margin: "20px" }}>
            <QRCode
              style={{
                width: "100%",
              }}
              value={qrPayment.qrCode}
              size={400}
              bordered={true}
              errorLevel="H"
            />
          </div>
        </Modal>
      )}

      <Modal
        title={
          <div style={{ display: "flex", alignItems: "center", gap: "8px" }}>
            <CreditCardOutlined />
            <span>Thông báo thanh toán</span>
          </div>
        }
        open={modalPayMentSuccess}
        onCancel={() => {
          setModalPayMentSuccess(false)
          window.location.reload()
        }}
        footer={[
          <Button
            key="cancel"
            onClick={() => {
              setModalPayMentSuccess(false)
              window.location.reload()
            }}
          >
            Đóng
          </Button>,
        ]}
        width={500}
      >
        {payMentSuccess ? (
          <Result
            status="success"
            title="Thanh toán thành công"
            subTitle="Cảm ơn bạn đã sử dụng dịch vụ. Giao dịch đã được xử lý."
          />
        ) : (
          <Result
            status="error"
            title="Thanh toán thất bại"
            subTitle="Đã có lỗi xảy ra trong quá trình xử lý. Vui lòng thử lại."
          />
        )}
      </Modal>
    </div>
  )
}

export default MembershipUpgrade
